                                    endValue = this._getBendNoteValue(note, note.bendPoints!![(note.bendPoints!!.length - (1.0).toDouble()).toInt()])
                                    endY = ((this.glyphs!![(0).toInt()] as com.omnifret.gplayer.rendering.glyphs.BendNoteHeadGroupGlyph)).getNoteValueY(endValue) + heightOffset
                                    this.drawBendSlur(
                                        canvas
                                        , 
                                        startX
                                        , 
                                        startY
                                        , 
                                        endBeatX
                                        , 
                                        endY
                                        , 
                                        direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down
                                        , 
                                        slurText
                                    
                                    )
                                }
                            }
                            else -> { }
                        }
                    }
                    i++
                }
            }
        }
    }
    
    /**
     */
    private fun _getBendNoteValue(note: com.omnifret.gplayer.model.Note, bendPoint: com.omnifret.gplayer.model.BendPoint): Double{
        return note.displayValueWithoutBend + (((bendPoint.value / (2.0).toDouble())).toInt() or 0)
    }
    
}

